CommandInNewTab {","      cwd = os.getenv('WEZTERM_CONFIG_DIR'),","      set_environment_variables = {","        TERM = 'screen-256color',","      },","      args = {","        'hx',","        os.getenv('WEZTERM_CONFIG_FILE'),","      },","    },","  },","  {","    key = 'LeftArrow',","    mods = 'LEADER',","    action = act.ActivatePaneDirection 'Left',","  },","  {","    key = 'RightArrow',","    mods = 'LEADER',","    action = act.ActivatePaneDirection 'Right',","  },","  {","    key = 'UpArrow',","    mods = 'LEADER',","    action = act.ActivatePaneDirection 'Up',","  },","  {","    key = 'DownArrow',","    mods = 'LEADER',","    action = act.ActivatePaneDirection 'Down',","  },","  {","    key = 'r',","    mods = 'LEADER',","    action = act.PromptInputLine {","      description = 'Enter new name for tab',","      action = wezterm.action_callback(function(window, _, line)","        -- line will be `nil` if they hit escape without entering anything","        -- An empty string if they just hit enter","        -- Or the actual line of text they wrote","        if line then","          window:active_tab():set_title(line)","        end","      end),","    },","  },","  {","    key = 'C',","    mods = 'CTRL',","    action = wezterm.action.CopyTo 'ClipboardAndPrimarySelection',","  },","  -- paste from the clipboard","  {","    key = 'V',","    mods = 'CTRL',","    action = act.PasteFrom 'Clipboard'","  },","  -- paste from the primary selection","  {","    key = 'V',","    mods = 'CTRL',","    action = act.PasteFrom 'PrimarySelection'","  },","}","","-- and finally, return the configuration to wezterm","return config"],"stylingDirectives":[[[0,26,"pl-c"],[0,2,"pl-c"]],[[0,5,"pl-k"],[6,13,"pl-smi"],[14,15,"pl-k"],[16,23,"pl-c1"],[24,33,"pl-s"],[24,25,"pl-pds"],[32,33,"pl-pds"]],[],[[0,36,"pl-c"],[0,2,"pl-c"]],[[0,5,"pl-k"],[6,12,"pl-smi"],[13,14,"pl-k"],[15,22,"pl-smi"],[23,37,"pl-c1"]],[],[[0,6,"pl-smi"],[7,19,"pl-e"],[20,21,"pl-k"],[22,31,"pl-s"],[22,23,"pl-pds"],[